def build_string_bad(chars):
    result = ""
    for c in chars:
        result += c  # new string every time!
    return result

print(build_string_bad(["h", "e", "l", "l", "o"]))

def build_string_good(chars):
    parts = []
    for c in chars:
        parts.append(c)
    return "".join(parts)

print(build_string_good(["h", "e", "l", "l", "o"]))
